template&lt;typename T&gt;
void swap(T&amp; a, T&amp; b) 
    noexcept(std::is_nothrow_move_constructible_v&lt;T&gt;)
{
    T temp{std::move(a)};
    a = std::move(b);
    b = std::move(temp);
}

